import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

const CertificateWall = () => {
  // 模拟证书数据
  const initialCertificates = [
    {
      id: 'GHU-BA-2023-123456',
      name: 'Sarah Johnson',
      program: 'Bachelor of Computer Science',
      country: 'United States',
      flag: '🇺🇸',
      issueDate: '2023-08-15',
      image: 'https://randomuser.me/api/portraits/women/44.jpg',
      achievements: ['Cum Laude', 'Capstone Excellence Award'],
    },
    {
      id: 'GHU-MA-2023-654321',
      name: 'Michael Chen',
      program: 'Master of Business Administration',
      country: 'Singapore',
      flag: '🇸🇬',
      issueDate: '2023-08-10',
      image: 'https://randomuser.me/api/portraits/men/22.jpg',
      achievements: ["Dean's List", 'Leadership Award'],
    },
    {
      id: 'GHU-PHD-2023-789012',
      name: 'Aisha Patel',
      program: 'Doctor of Philosophy in Data Science',
      country: 'India',
      flag: '🇮🇳',
      issueDate: '2023-08-05',
      image: 'https://randomuser.me/api/portraits/women/63.jpg',
      achievements: ['Research Excellence', 'Outstanding Dissertation'],
    },
    {
      id: 'GHU-PC-2023-345678',
      name: 'James Wilson',
      program: 'Professional Certificate in Cybersecurity',
      country: 'United Kingdom',
      flag: '🇬🇧',
      issueDate: '2023-08-02',
      image: 'https://randomuser.me/api/portraits/men/32.jpg',
      achievements: ['Top Performer'],
    },
    {
      id: 'GHU-BA-2023-901234',
      name: 'Emma Rodriguez',
      program: 'Bachelor of Arts in International Relations',
      country: 'Mexico',
      flag: '🇲🇽',
      issueDate: '2023-07-29',
      image: 'https://randomuser.me/api/portraits/women/28.jpg',
      achievements: ['Honors Program', 'Study Abroad Excellence'],
    },
    {
      id: 'GHU-MS-2023-567890',
      name: 'David Kim',
      program: 'Master of Science in Artificial Intelligence',
      country: 'South Korea',
      flag: '🇰🇷',
      issueDate: '2023-07-25',
      image: 'https://randomuser.me/api/portraits/men/42.jpg',
      achievements: ['Research Publication Award'],
    },
    {
      id: 'GHU-PC-2023-234567',
      name: 'Olivia Müller',
      program: 'Professional Certificate in Digital Marketing',
      country: 'Germany',
      flag: '🇩🇪',
      issueDate: '2023-07-20',
      image: 'https://randomuser.me/api/portraits/women/52.jpg',
      achievements: ['Campaign Excellence'],
    },
    {
      id: 'GHU-BA-2023-890123',
      name: 'Mohammed Al-Farsi',
      program: 'Bachelor of Business Administration',
      country: 'United Arab Emirates',
      flag: '🇦🇪',
      issueDate: '2023-07-15',
      image: 'https://randomuser.me/api/portraits/men/59.jpg',
      achievements: ['Business Innovation Challenge Winner'],
    },
    {
      id: 'GHU-MA-2023-456789',
      name: 'Fatima Zahra',
      program: 'Master of Arts in Educational Leadership',
      country: 'Morocco',
      flag: '🇲🇦',
      issueDate: '2023-07-10',
      image: 'https://randomuser.me/api/portraits/women/36.jpg',
      achievements: ['Educational Reform Project Award'],
    },
    {
      id: 'GHU-PHD-2023-012345',
      name: 'Carlos Mendoza',
      program: 'Doctor of Philosophy in Environmental Science',
      country: 'Brazil',
      flag: '🇧🇷',
      issueDate: '2023-07-05',
      image: 'https://randomuser.me/api/portraits/men/67.jpg',
      achievements: ['Sustainability Research Award', 'Field Work Excellence'],
    },
    {
      id: 'GHU-PC-2023-678901',
      name: 'Liu Wei',
      program: 'Professional Certificate in Project Management',
      country: 'China',
      flag: '🇨🇳',
      issueDate: '2023-07-01',
      image: 'https://randomuser.me/api/portraits/men/79.jpg',
      achievements: ['PMP Excellence'],
    },
    {
      id: 'GHU-BA-2023-345678',
      name: 'Grace Okafor',
      program: 'Bachelor of Science in Nursing',
      country: 'Nigeria',
      flag: '🇳🇬',
      issueDate: '2023-06-25',
      image: 'https://randomuser.me/api/portraits/women/75.jpg',
      achievements: ['Clinical Excellence Award'],
    },
  ];

  // 统计数据
  const stats = {
    totalCertificates: 8742,
    countriesRepresented: 124,
    averageSatisfaction: 4.8,
    topPrograms: [
      'Business Administration',
      'Computer Science',
      'Data Science',
      'Project Management',
      'Digital Marketing',
    ],
  };

  // 状态
  const [certificates, setCertificates] = useState(initialCertificates);
  const [filteredCertificates, setFilteredCertificates] = useState(initialCertificates);
  const [verifyId, setVerifyId] = useState('');
  const [verifyResult, setVerifyResult] = useState(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedProgram, setSelectedProgram] = useState('All');
  const [isVerifying, setIsVerifying] = useState(false);

  // 所有可用的项目类型
  const programTypes = [
    'All',
    'Bachelor',
    'Master',
    'Doctor of Philosophy',
    'Professional Certificate',
  ];

  // 处理证书验证
  const handleVerify = e => {
    e.preventDefault();
    if (!verifyId.trim()) return;

    setIsVerifying(true);

    // 模拟API调用延迟
    setTimeout(() => {
      const foundCertificate = initialCertificates.find(cert => cert.id === verifyId);

      if (foundCertificate) {
        setVerifyResult({
          valid: true,
          certificate: foundCertificate,
        });
      } else {
        setVerifyResult({
          valid: false,
          message: 'Certificate not found. Please check the ID and try again.',
        });
      }

      setIsVerifying(false);
    }, 1000);
  };

  // 处理搜索和过滤
  useEffect(() => {
    let results = initialCertificates;

    // 按程序类型过滤
    if (selectedProgram !== 'All') {
      results = results.filter(cert => cert.program.includes(selectedProgram));
    }

    // 按姓名或证书ID搜索
    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      results = results.filter(
        cert =>
          cert.name.toLowerCase().includes(query) ||
          cert.id.toLowerCase().includes(query) ||
          cert.program.toLowerCase().includes(query) ||
          cert.country.toLowerCase().includes(query)
      );
    }

    setFilteredCertificates(results);
  }, [searchQuery, selectedProgram]);

  // 格式化日期
  const formatDate = dateString => {
    const options = { year: 'numeric', month: 'long', day: 'numeric' };
    return new Date(dateString).toLocaleDateString('en-US', options);
  };

  return (
    <div className="bg-gray-50 min-h-screen pb-16">
      {/* 页面标题 */}
      <div className="bg-gradient-to-r from-blue-900 to-purple-900 py-16">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <h1 className="text-4xl font-bold text-white text-center">Global Certificate Wall</h1>
          <p className="mt-4 text-xl text-gray-200 text-center max-w-3xl mx-auto">
            Celebrating academic achievements from around the world
          </p>
        </div>
      </div>

      {/* 主要内容区域 - 移除了网格布局 */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <div className="flex flex-col space-y-8">
          {/* 搜索和过滤区域 */}
          <div className="bg-white rounded-lg shadow-md p-6">
            <div className="flex flex-col md:flex-row md:justify-between items-start md:items-center mb-6 space-y-4 md:space-y-0 md:space-x-4">
              <div className="relative w-full md:w-auto">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <svg
                    className="h-5 w-5 text-gray-400"
                    xmlns="http://www.w3.org/2000/svg"
                    fill="none"
                    viewBox="0 0 24 24"
                    stroke="currentColor"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"
                    />
                  </svg>
                </div>
                <input
                  type="text"
                  className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-md leading-5 bg-white placeholder-gray-500 focus:outline-none focus:placeholder-gray-400 focus:ring-1 focus:ring-blue-500 focus:border-blue-500 sm:text-sm"
                  placeholder="Search certificates..."
                  value={searchQuery}
                  onChange={e => setSearchQuery(e.target.value)}
                />
              </div>

              <div className="w-full md:w-auto">
                <label htmlFor="program-filter" className="sr-only">
                  Filter by program
                </label>
                <select
                  id="program-filter"
                  className="block w-full pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm rounded-md"
                  value={selectedProgram}
                  onChange={e => setSelectedProgram(e.target.value)}
                >
                  {programTypes.map(type => (
                    <option key={type} value={type}>
                      {type}
                    </option>
                  ))}
                </select>
              </div>
            </div>

            {/* 验证证书区域 */}
            <div className="mb-6">
              <h2 className="text-xl font-semibold text-gray-900 mb-4">Verify a Certificate</h2>
              <form onSubmit={handleVerify} className="flex flex-col sm:flex-row space-y-3 sm:space-y-0 sm:space-x-4">
                <div className="flex-1">
                  <input
                    type="text"
                    id="certificate-id"
                    className="block w-full px-4 py-2 border border-gray-300 rounded-md shadow-sm placeholder-gray-400 focus:outline-none focus:ring-blue-500 focus:border-blue-500"
                    placeholder="e.g. GHU-BA-2023-123456"
                    value={verifyId}
                    onChange={e => setVerifyId(e.target.value)}
                  />
                </div>
                <button
                  type="submit"
                  className="px-6 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-blue-500 hover:bg-blue-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                  disabled={isVerifying}
                >
                  {isVerifying ? 'Verifying...' : 'Verify Certificate'}
                </button>
              </form>
              
              {/* 验证结果 */}
              {verifyResult && (
                <div
                  className={`mt-4 p-4 rounded-md ${verifyResult.valid ? 'bg-green-50 border border-green-200' : 'bg-red-50 border border-red-200'}`}
                >
                  {verifyResult.valid ? (
                    <div className="flex items-start">
                      <svg
                        className="h-6 w-6 text-green-600 mr-2 mt-1 flex-shrink-0"
                        xmlns="http://www.w3.org/2000/svg"
                        fill="none"
                        viewBox="0 0 24 24"
                        stroke="currentColor"
                      >
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          strokeWidth="2"
                          d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"
                        />
                      </svg>
                      <div>
                        <h3 className="text-lg font-semibold text-green-800">Certificate is Valid!</h3>
                        <p className="text-sm text-green-700 mb-2">This certificate has been verified as authentic.</p>
                        <div className="text-sm text-gray-700 space-y-1">
                          <div><span className="font-medium">Name:</span> {verifyResult.certificate.name}</div>
                          <div><span className="font-medium">Program:</span> {verifyResult.certificate.program}</div>
                          <div><span className="font-medium">Issue Date:</span> {formatDate(verifyResult.certificate.issueDate)}</div>
                          <div><span className="font-medium">Country:</span> {verifyResult.certificate.flag} {verifyResult.certificate.country}</div>
                        </div>
                      </div>
                    </div>
                  ) : (
                    <div className="flex items-center">
                      <svg
                        className="h-6 w-6 text-red-600 mr-2"
                        xmlns="http://www.w3.org/2000/svg"
                        fill="none"
                        viewBox="0 0 24 24"
                        stroke="currentColor"
                      >
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          strokeWidth="2"
                          d="M10 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2m7-2a9 9 0 11-18 0 9 9 0 0118 0z"
                        />
                      </svg>
                      <div>
                        <h3 className="text-lg font-semibold text-red-800">Invalid Certificate</h3>
                        <p className="text-sm text-red-700">{verifyResult.message}</p>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>

          {/* 证书列表 - 移除了网格布局，改为单列显示 */}
          <div className="bg-white rounded-lg shadow-md p-6">
            <h2 className="text-2xl font-bold text-gray-900 mb-6">Recently Issued Certificates</h2>

            {filteredCertificates.length > 0 ? (
              <div className="space-y-4">
                {filteredCertificates.map(certificate => (
                  <div
                    key={certificate.id}
                    className="bg-gray-50 rounded-lg p-4 border border-gray-200 hover:shadow-md transition-shadow duration-300"
                  >
                    <div className="flex items-start">
                      <img
                        src={certificate.image}
                        alt={certificate.name}
                        className="h-16 w-16 rounded-full object-cover"
                      />
                      <div className="ml-4 flex-1">
                        <div className="flex items-center justify-between">
                          <h3 className="text-lg font-semibold text-gray-900">{certificate.name}</h3>
                          <div className="flex items-center text-lg">
                            <span title={certificate.country}>{certificate.flag}</span>
                          </div>
                        </div>
                        <p className="text-sm text-blue-800">{certificate.program}</p>
                        <div className="mt-2 flex justify-between items-center">
                          <p className="text-xs text-gray-500">Issued: {formatDate(certificate.issueDate)}</p>
                          <button
                            onClick={() => {
                              setVerifyId(certificate.id);
                              handleVerify({ preventDefault: () => {} });
                            }}
                            className="text-xs text-blue-900 hover:text-blue-700 font-medium flex items-center"
                          >
                            <svg className="h-3 w-3 mr-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
                            </svg>
                            Verify →
                          </button>
                        </div>
                        
                        {certificate.achievements && certificate.achievements.length > 0 && (
                          <div className="mt-3 pt-3 border-t border-gray-200">
                            <div className="flex flex-wrap gap-2">
                              {certificate.achievements.map((achievement, idx) => (
                                <span
                                  key={idx}
                                  className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800"
                                >
                                  {achievement}
                                </span>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="text-center py-12">
                <svg
                  className="mx-auto h-12 w-12 text-gray-400"
                  xmlns="http://www.w3.org/2000/svg"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"
                  />
                </svg>
                <h3 className="mt-2 text-sm font-medium text-gray-900">No certificates found</h3>
                <p className="mt-1 text-sm text-gray-500">Try adjusting your search or filter criteria.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default CertificateWall;
